class Solution:
    def unmarkedSumArray(self, nums, queries):
        n = len(nums)
        marked = [False] * n
        ans = []
        for idx, k in queries:
            if not marked[idx]:
                marked[idx] = True
            order = sorted((i for i in range(n) if not marked[i]), key=lambda i: (nums[i], i))
            for i in order[:k]:
                marked[i] = True
            ans.append(sum(nums[i] for i in range(n) if not marked[i]))
        return ans

