var unmarkedSumArray = function(nums, queries) {
    const n = nums.length;
    const marked = new Array(n).fill(false);
    const cmp = (a, b) => a[0] !== b[0] ? a[0] - b[0] : a[1] - b[1];
    const heap = [];
    const push = (x) => {
        heap.push(x);
        let i = heap.length - 1;
        while (i > 0) {
            const p = (i - 1) >> 1;
            if (cmp(heap[i], heap[p]) < 0) { [heap[i], heap[p]] = [heap[p], heap[i]]; i = p; }
            else break;
        }
    };
    const pop = () => {
        const top = heap[0];
        const last = heap.pop();
        if (heap.length) {
            heap[0] = last;
            let i = 0;
            while (true) {
                let l = 2 * i + 1, r = 2 * i + 2, s = i;
                if (l < heap.length && cmp(heap[l], heap[s]) < 0) s = l;
                if (r < heap.length && cmp(heap[r], heap[s]) < 0) s = r;
                if (s === i) break;
                [heap[i], heap[s]] = [heap[s], heap[i]]; i = s;
            }
        }
        return top;
    };
    let total = 0;
    for (let i = 0; i < n; i++) { push([nums[i], i]); total += nums[i]; }
    const ans = [];
    for (const [idx, k] of queries) {
        if (!marked[idx]) { marked[idx] = true; total -= nums[idx]; }
        let cnt = 0;
        while (cnt < k && heap.length) {
            const [v, i] = pop();
            if (marked[i]) continue;
            marked[i] = true; total -= v; cnt++;
        }
        ans.push(total);
    }
    return ans;
};
